import{_ as a,o as t,c as r,ak as o,av as s,aw as c,ax as d}from"./chunks/framework.D56sOg_b.js";const f=JSON.parse('{"title":"Squaretest Java 单元测试生成器","description":"","frontmatter":{"version":"2.0.0"},"headers":[],"relativePath":"other/crack/square-test.md","filePath":"other/crack/square-test.md","lastUpdated":1777342039000}'),i={name:"other/crack/square-test.md"};function n(l,e,p,h,_,m){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="squaretest-java-单元测试生成器" tabindex="-1">Squaretest Java 单元测试生成器 <a class="header-anchor" href="#squaretest-java-单元测试生成器" aria-label="Permalink to “Squaretest Java 单元测试生成器”">​</a></h1><p><code>Squaretest</code> 是 IntelliJ IDEA 的单元测试生成插件，可用于为 Java 源类自动生成测试类和测试方法。</p><p>生成的测试类通常包含源类实例构造、依赖初始化、Mockito 存根以及方法调用结果校验等内容。</p><h2 id="为-java-类创建测试类" tabindex="-1">为 Java 类创建测试类 <a class="header-anchor" href="#为-java-类创建测试类" aria-label="Permalink to “为 Java 类创建测试类”">​</a></h2><ul><li><p>选择 <strong>Squaretest | Generate Test - Ask to Confirm Mocks</strong>（<code>Alt+Insert</code> -&gt; <code>Generate Test - Ask to Confirm Mocks</code>）为 Java 源类生成测试类。 <img src="'+s+'" alt="生成测试动图"></p></li><li><p>也可使用可配置的快捷键生成测试类：Windows 和 Linux 默认为 <code>Ctrl+Alt+K</code>，macOS 默认为 <code>Cmd+Shift+L</code>。</p></li></ul><h2 id="创建默认的测试方法" tabindex="-1">创建默认的测试方法 <a class="header-anchor" href="#创建默认的测试方法" aria-label="Permalink to “创建默认的测试方法”">​</a></h2><p>选择 <strong>Squaretest | 生成测试方法</strong>（<code>Alt+Insert</code> -&gt; <code>生成测试方法</code>），可查看当前类可添加的测试方法列表。</p><p>该列表通常会包含源方法的不同执行分支示例。例如，当源方法调用 <code>foo.bar()</code> 且 <code>bar()</code> 可能抛出 <code>IOException</code> 时，Squaretest 会建议生成类似 <code>testMethodName_FooThrowsIOException()</code> 的测试方法。</p><p><img src="'+c+'" alt="生成测试方法 Gif"></p><h2 id="根据建议创建测试方法" tabindex="-1">根据建议创建测试方法 <a class="header-anchor" href="#根据建议创建测试方法" aria-label="Permalink to “根据建议创建测试方法”">​</a></h2><p>输入目标测试方法名称后，插件会基于源类方法给出候选建议。选择对应建议后即可生成相应测试方法。</p><p><img src="'+d+'" alt="生成测试方法 Gif"></p>',12)])])}const k=a(i,[["render",n]]);expo